"""Configuration settings for agentic AI project."""import osfrom pathlib import Pathfrom typing import Optional# Project pathsPROJECT_ROOT = Path(__file__).parent.parent.parentASSETS_DIR = PROJECT_ROOT / "assets"IMAGES_DIR = ASSETS_DIR / "images"PROMPTS_DIR = ASSETS_DIR / "prompts"DATA_DIR = PROJECT_ROOT / "data"EXAMPLES_DIR = PROJECT_ROOT / "examples"# Model configurationsDEFAULT_ANTHROPIC_MODEL = "claude-haiku-4-5-20251001"ADVANCED_ANTHROPIC_MODEL = "claude-sonnet-4-6"# API KeysANTHROPIC_API_KEY = os.getenv("ANTHROPIC_API_KEY")JIRA_URL = os.getenv("JIRA_URL")JIRA_USERNAME = os.getenv("JIRA_USERNAME")JIRA_API_TOKEN = os.getenv("JIRA_API_TOKEN")# Runtime settingsMAX_RETRIES = 5DEFAULT_TIMEOUT = 60def get_asset_path(asset_type: str, filename: str) -> Path:    """Get path to an asset file."""    if asset_type == "image":        return IMAGES_DIR / filename    elif asset_type == "prompt":        return PROMPTS_DIR / filename    else:        raise ValueError(f"Unknown asset type: {asset_type}")def get_data_path(filename: str) -> Path:    """Get path to a data file."""    return DATA_DIR / filenamedef validate_environment() -> dict:    """Validate required environment variables."""    missing = []    if not ANTHROPIC_API_KEY:        missing.append("ANTHROPIC_API_KEY")    return {        "valid": len(missing) == 0,        "missing": missing    }